<template><view class="page"><view v-if="loading" class="empty">会员信息读取中</view><block v-else-if="data"><view class="hero"><text class="hero-name">{{ data.current_level?.name || '普通会员' }}</text><text class="hero-sub">成长值 {{ data.growth_value }} · 积分 {{ data.points }}</text><text v-if="data.vip_expired_at" class="hero-expire">权益有效至 {{ data.vip_expired_at }}</text><view class="hero-stats"><view><text>¥{{ data.total_spent }}</text><text>累计消费</text></view><view><text>{{ data.coupon_count }}</text><text>可用优惠券</text></view></view></view><view class="section"><text class="title">当前会员权益</text><block v-if="data.current_level"><view class="benefit"><text>订单折扣 {{ Number(data.current_level.discount_rate) * 10 }} 折</text><text>押金优惠 ¥{{ data.current_level.deposit_discount }}</text></view><view v-if="benefitList.length" class="benefit-list"><text v-for="item in benefitList" :key="item" class="benefit-item">{{ item }}</text></view></block><text v-else class="note">完成订单并累计成长值，可解锁更多会员权益。</text></view><view class="section"><text class="title">会员等级</text><view v-for="level in data.levels" :key="level.id" class="level"><view><text class="level-name">{{ level.name }}</text><text class="level-note">成长值 {{ level.min_growth_value }} 起</text></view><text class="level-discount">{{ Number(level.discount_rate) * 10 }} 折</text></view></view><view class="actions"><button @click="goPoints">积分明细</button><button class="secondary" @click="goCoupons">领券中心</button></view></block></view></template>
<script setup>import{computed,ref}from'vue';import{onShow}from'@dcloudio/uni-app';import{getMemberOverview}from'../../api/member';const loading=ref(true),data=ref(null);const benefitList=computed(()=>{const b=data.value?.current_level?.benefits||{};return Object.entries(b).map(([k,v])=>`${k}：${typeof v==='object'?JSON.stringify(v):v}`)});const load=async()=>{loading.value=true;try{data.value=(await getMemberOverview()).data||null}catch(e){uni.showToast({title:e.msg||'读取失败',icon:'none'})}finally{loading.value=false}};const goPoints=()=>uni.navigateTo({url:'/pages/profile/points'});const goCoupons=()=>uni.navigateTo({url:'/pages/profile/coupons'});onShow(load)</script>
<style scoped>.page{min-height:100vh;padding:28rpx 32rpx;background:#f5f7fa}.hero,.section{margin-bottom:20rpx;padding:28rpx;border-radius:8rpx;background:#fff}.hero{background:#1f2937;color:#fff}.hero-name{display:block;font-size:38rpx;font-weight:700}.hero-sub,.hero-expire{display:block;margin-top:12rpx;color:#d1d5db;font-size:24rpx}.hero-expire{color:#fbbf24;font-size:22rpx}.hero-stats{display:flex;margin-top:28rpx}.hero-stats view{display:flex;flex:1;flex-direction:column}.hero-stats text:first-child{font-size:30rpx;font-weight:700}.hero-stats text:last-child{margin-top:8rpx;color:#cbd5e1;font-size:21rpx}.title{display:block;margin-bottom:18rpx;color:#1f2937;font-size:29rpx;font-weight:700}.benefit,.level{display:flex;justify-content:space-between;gap:20rpx;color:#374151;font-size:24rpx}.benefit-list{display:flex;flex-wrap:wrap;gap:10rpx;margin-top:18rpx}.benefit-item{padding:8rpx 12rpx;border-radius:4rpx;background:#eff6ff;color:#1677ff;font-size:21rpx}.note,.level-note{color:#9ca3af;font-size:23rpx;line-height:1.5}.level{align-items:center;padding:20rpx 0;border-bottom:1rpx solid #eef0f4}.level:last-child{border-bottom:0}.level-name{display:block;font-size:26rpx;font-weight:700}.level-note{display:block;margin-top:8rpx}.level-discount{color:#f97316;font-size:27rpx;font-weight:700}.actions{display:flex;gap:16rpx}.actions button{flex:1;border-radius:8rpx;background:#1677ff;color:#fff;font-size:26rpx}.actions .secondary{background:#fff;color:#1677ff;border:1rpx solid #bfdbfe}.empty{padding:180rpx 0;color:#9ca3af;text-align:center;font-size:26rpx}</style>
